SELECT
    COUNT(*) AS row_count,
    ROUND(
        AVG(
            ABS(actual_revenue - (list_revenue * (1 - discount_rate) - coupon_amount))
        ),
        4
    ) AS avg_abs_diff,
    ROUND(
        MAX(
            ABS(actual_revenue - (list_revenue * (1 - discount_rate) - coupon_amount))
        ),
        4
    ) AS max_abs_diff,
    ROUND(
        AVG(
            ABS(actual_revenue - (list_revenue * (1 - discount_rate) - coupon_amount))
            / NULLIF(actual_revenue, 0)
        ),
        6
    ) AS avg_relative_diff
FROM fact_actual_revenue;
